const ACCESS_COOKIE = "proxyip_access";
const ACCESS_VALUE = "ok";
const ACCESS_TTL = 60 * 60 * 8;
const TEXT_PATHS = new Set(["/current.txt", "/standby.txt", "/all.txt", "/us.txt", "/best.txt", "/top5.txt", "/v2ray.txt"]);
const JSON_PATHS = new Set(["/current.json", "/state.json", "/history.json", "/full.json", "/health"]);
const BLOCKED_UA = /(bot|spider|crawler|scrapy|python-requests|aiohttp|curl|wget|go-http-client|httpx|masscan|zgrab|nuclei|semrush|ahrefs|bytespider|petalbot|yandex|bingbot|googlebot)/i;

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const result = await loadResult(env);
    const valid = Array.isArray(result.valid_ips) ? result.valid_ips : [];
    const ips = valid.map((item) => item.ip).filter(Boolean);

    if (request.method === "OPTIONS") return withHeaders(new Response(null, { status: 204 }));
    if (request.method !== "GET") return withHeaders(new Response("Method not allowed", { status: 405 }));
    if (url.pathname === "/robots.txt") return text("User-agent: *\nDisallow: /\n", false);

    if (TEXT_PATHS.has(url.pathname) || JSON_PATHS.has(url.pathname)) {
      const gate = checkAccess(request, url);
      if (!gate.ok) return deny(gate.reason);
    }

    if (url.pathname === "/current.txt") return text(lines(currentIp(result) ? [currentIp(result)] : []), true);
    if (url.pathname === "/standby.txt") return text(lines(standby(result).map((item) => item.ip).filter(Boolean)), true);
    if (url.pathname === "/all.txt" || url.pathname === "/us.txt") return text(lines(ips), true);
    if (url.pathname === "/best.txt") {
      const n = Math.min(Math.max(Number.parseInt(url.searchParams.get("n") || "20", 10) || 20, 1), 100);
      return text(lines(ips.slice(0, n)), true);
    }
    if (url.pathname === "/top5.txt") return text(lines(top5(result)), true);
    if (url.pathname === "/v2ray.txt") return text(btoa(ips.join("\n")), true);
    if (url.pathname === "/current.json") return json({ current: result.current || null, state: result.state || null }, true);
    if (url.pathname === "/state.json") return json(result.state || {}, true);
    if (url.pathname === "/history.json") return json(result.history || [], true);
    if (url.pathname === "/full.json") return json(result, true);
    if (url.pathname === "/health") return json({ ok: true, current: currentIp(result), standby_count: standby(result).length, count: ips.length, checked_at: result.summary?.checked_at || null }, true);

    return html(renderHome(result, url));
  }
};

async function loadResult(env) {
  if (env.PROXYIP_KV) {
    const stored = await env.PROXYIP_KV.get("result_json", "json");
    if (stored) return stored;
  }
  return DEFAULT_RESULT;
}

function checkAccess(request, url) {
  const ua = request.headers.get("user-agent") || "";
  if (BLOCKED_UA.test(ua)) return { ok: false, reason: "blocked user-agent" };
  if (url.searchParams.get("t") === todayToken()) return { ok: true };
  if ((request.headers.get("cookie") || "").includes(`${ACCESS_COOKIE}=${ACCESS_VALUE}`)) return { ok: true };
  return { ok: false, reason: "open the homepage first, or add ?t=YYYYMMDD" };
}

function todayToken() {
  return new Date().toISOString().slice(0, 10).replace(/-/g, "");
}

function currentIp(result) {
  return result.current?.ip || result.state?.current_ip || null;
}
function standby(result) {
  return Array.isArray(result.standby) ? result.standby : [];
}
function top5(result) {
  return (Array.isArray(result.recommended_top5) ? result.recommended_top5 : []).map((item) => item.ip).filter(Boolean);
}

function renderHome(result, url) {
  const s = result.summary || {};
  const valid = Array.isArray(result.valid_ips) ? result.valid_ips : [];
  const token = todayToken();
  const rows = valid.slice(0, 30).map((item, i) => `<tr><td>${i + 1}</td><td><code>${escapeHtml(item.ip)}</code></td><td>${escapeHtml(item.portRemote || 443)}</td><td>${escapeHtml(item.colo || "")}</td><td>${escapeHtml(item.latency_ms ?? "")}</td></tr>`).join("");
  return `<!doctype html><html lang="zh-Hant"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="robots" content="noindex,nofollow,noarchive"><title>ProxyIP US IPv4</title><style>body{font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;max-width:960px;margin:40px auto;padding:0 20px;line-height:1.55;color:#111827}a{color:#2563eb}code{background:#f3f4f6;padding:2px 5px;border-radius:4px}.card{display:inline-block;border:1px solid #e5e7eb;border-radius:12px;padding:14px 18px;margin:6px 8px 6px 0;background:#fafafa}.card b{display:block;font-size:24px}table{width:100%;border-collapse:collapse;margin-top:14px}td,th{border-bottom:1px solid #e5e7eb;padding:9px;text-align:left}.muted{color:#6b7280}.ok{color:#047857}</style></head><body><h1>ProxyIP US IPv4</h1><p class="muted">只收錄 <code>https://zip.cm.edu.kg/all.txt</code> 中標記 <code>#US</code>、端口 <code>443</code>、且 cmliu 檢測 <code>supports_ipv4=true</code> 的結果。</p><div class="card">cmliu valid<b class="ok">${escapeHtml(s.cmliu_ipv4_valid ?? valid.length)}</b></div><div class="card">candidates<b>${escapeHtml(s.total_candidates ?? valid.length)}</b></div><div class="card">checked<b>${escapeHtml(s.checked_at || "unknown")}</b></div><h2>Current Stable ProxyIP</h2><p><code>${escapeHtml(currentIp(result) || "none")}</code></p><h2>Endpoints</h2><ul><li><a href="/current.txt?t=${token}">current.txt</a></li><li><a href="/current.json?t=${token}">current.json</a></li><li><a href="/standby.txt?t=${token}">standby.txt</a></li><li><a href="/all.txt?t=${token}">all.txt</a></li><li><a href="/us.txt?t=${token}">us.txt</a></li><li><a href="/top5.txt?t=${token}">top5.txt</a></li><li><a href="/best.txt?t=${token}">best.txt</a></li><li><a href="/history.json?t=${token}">history.json</a></li><li><a href="/full.json?t=${token}">full.json</a></li><li><a href="/v2ray.txt?t=${token}">v2ray.txt</a></li></ul><p class="muted">接口有基礎反爬保護：需先訪問首頁取得 cookie，或使用當天 token <code>?t=YYYYMMDD</code>。</p><h2>Top 30</h2><table><thead><tr><th>#</th><th>IP</th><th>Port</th><th>Colo</th><th>Latency ms</th></tr></thead><tbody>${rows}</tbody></table></body></html>`;
}

function lines(items) {
  return items.join("\n") + (items.length ? "\n" : "");
}
function deny(reason) {
  return withHeaders(new Response(reason + "\n", { status: 403, headers: { "content-type": "text/plain; charset=utf-8" } }), false);
}
function html(body) {
  return withHeaders(new Response(body, { headers: { "content-type": "text/html; charset=utf-8", "set-cookie": `${ACCESS_COOKIE}=${ACCESS_VALUE}; Max-Age=${ACCESS_TTL}; Path=/; Secure; HttpOnly; SameSite=Lax` } }), false);
}
function text(body, privateCache) {
  return withHeaders(new Response(body, { headers: { "content-type": "text/plain; charset=utf-8" } }), privateCache);
}
function json(data, privateCache) {
  return withHeaders(new Response(JSON.stringify(data, null, 2), { headers: { "content-type": "application/json; charset=utf-8" } }), privateCache);
}
function withHeaders(response, privateCache = false) {
  const headers = new Headers(response.headers);
  headers.set("access-control-allow-origin", "*");
  headers.set("cache-control", privateCache ? "private, max-age=300" : "public, max-age=300");
  headers.set("x-robots-tag", "noindex, nofollow, noarchive");
  headers.set("x-content-type-options", "nosniff");
  headers.set("referrer-policy", "no-referrer");
  return new Response(response.body, { status: response.status, statusText: response.statusText, headers });
}
function escapeHtml(value) {
  return String(value).replace(/[&<>"]/g, (ch) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[ch]));
}
